UPDATE
  `pcb-{env}-landing.domain_customer_acquisition.ADM_RT_RESPONSE_UNS` RTU
SET
  RTU.PC_MC_CUST_APPL_ID = RT.PC_MC_CUST_APPL_ID
FROM
  (
    SELECT DISTINCT
      A.APA_APP_NUM,
      A.PC_MC_CUST_APPL_ID
    FROM
      `pcb-{env}-curated.domain_customer_acquisition.ADM_RT_RESPONSE` A
    WHERE
      A.APA_APP_NUM IN (
3455420,3455440,3455437,3455434,3455436,3455442,3455447,3455455,3455449,3455462,3455458,3455464,3455470,3455480,
3455481,3455485,3455486,3455489,3455490,3455491,3455492,3455494,3455496,3455499,3455500,3455502,3455503,3455505,
3455506,3455507,3455510,3455511,3455512,3455514,3455516,3455518,3455521,3455522,3455524,3455526,3455527,3455528,
3455531,3455532,3455534,3455536,3455538,3455539,3455540,3455542,3455543,3455547,3455548,3455550,3455554,3455556,
3455558,3455562,3455563,3455564,3455565,3455568,3455569,3455570,3455572,3455573,3455575,3455576,3455579,3455580,
3455581,3455582,3455583,3455585,3455588,3455590,3455591,3455592,3455597,3455600,3455599,3455602,3455604,3455606,
3455608,3455609,3455610,3455612,3455615,3455616,3455617,3455619,3455621,3455622,3455625,3455627,3455629,3455630,
3455633,3455635,3455639,3455641,3455642,3455644,3455646,3455647,3455650,3455652,3455653,3455654)
  ) AS RT
WHERE
  RT.APA_APP_NUM = RTU.APA_APP_NUM
  AND RTU.PC_MC_CUST_APPL_ID IS NULL;
